// Robustes Parsing + Schema-Defaults + Sanity-Checks + QA-Band.
const MAX_LEN = 2500;
const MIN_MAIL_LEN = 120;
const clamp = (s) => (typeof s === 'string' ? s.substring(0, MAX_LEN) : '');

const raw = ($input.item.json.output || $input.item.json.result || '').toString();
const match = raw.match(/\{[\s\S]*\}/);
let parsed;
try {
  parsed = JSON.parse(match ? match[0] : raw);
} catch (e) {
  parsed = { _parse_error: e.message };
}
if (typeof parsed !== 'object' || parsed === null) parsed = {};

// Schema-Defaults — garantiert alle erwarteten Keys, egal was der LLM liefert:
parsed.klassifikation = parsed.klassifikation || { sparte: 'unbekannt', schadenart: 'unbekannt', dringlichkeit: 'standard' };
parsed.sofort_massnahmen = Array.isArray(parsed.sofort_massnahmen) ? parsed.sofort_massnahmen : [];
if (!parsed.sofort_massnahmen.length) parsed.sofort_massnahmen = ['Bitte manuell pruefen — kein strukturierter Output vom LLM.'];
parsed.mail_an_kunden = clamp((typeof parsed.mail_an_kunden === 'string' && parsed.mail_an_kunden.trim()) ? parsed.mail_an_kunden : raw);
parsed.mail_an_versicherer = clamp((typeof parsed.mail_an_versicherer === 'string' && parsed.mail_an_versicherer.trim()) ? parsed.mail_an_versicherer : raw);
parsed.sofort_massnahmen_text = parsed.sofort_massnahmen.map(s => '- ' + s).join('\n');

// Sanity-Checks → Warnungen fuer Makler-Review
const warnings = [];
if (!parsed.klassifikation.sparte || /unbekannt|unknown|n\/a/i.test(parsed.klassifikation.sparte)) warnings.push('Sparte nicht klassifiziert');
if (!parsed.klassifikation.schadenart || /unbekannt|unknown|n\/a/i.test(parsed.klassifikation.schadenart)) warnings.push('Schadenart nicht klassifiziert');
if (parsed.sofort_massnahmen.every(s => typeof s === 'string' && s.trim().length < 15)) warnings.push('Sofort-Massnahmen zu kurz/unspezifisch');
if (parsed.mail_an_kunden.length < MIN_MAIL_LEN) warnings.push('Kundenmail ungewoehnlich kurz (<' + MIN_MAIL_LEN + ' Zeichen)');
if (parsed.mail_an_versicherer.length < MIN_MAIL_LEN) warnings.push('Versicherer-Mail ungewoehnlich kurz (<' + MIN_MAIL_LEN + ' Zeichen)');
if (parsed.mail_an_kunden.length === MAX_LEN) warnings.push('Kundenmail auf ' + MAX_LEN + ' Zeichen gekuerzt');
parsed.warnings = warnings;

// QA-Band (Interpretation des qa_score fuer Makler):
const score = Number($input.item.json.qa_score) || 0;
let qa_band, qa_band_label;
if (score >= 0.9)      { qa_band = 'hoch';   qa_band_label = 'hoch verlaesslich — Drafts direkt freigeben'; }
else if (score >= 0.75) { qa_band = 'mittel'; qa_band_label = 'entwurfsreif — vor Versand durchlesen'; }
else                     { qa_band = 'niedrig'; qa_band_label = 'manuelle Pruefung zwingend'; }
parsed.qa_band = qa_band;
parsed.qa_band_label = qa_band_label;

return { json: { ...$input.item.json, parsed } };

